def shortest_tunnel_path(n, tunnels, k, air_stations, start, end):
    import heapq

    adj = [[] for _ in range(n)]
    for u, v, time, flooded in tunnels:
        adj[u].append((v, time, flooded))
        adj[v].append((u, time, flooded))

    air_set = set(air_stations)

    INF = float('inf')
    dist = [[INF] * (k + 1) for _ in range(n)]

    init_oxy = k
    dist[start][init_oxy] = 0

    pq = [(0, start, init_oxy)]

    while pq:
        t, u, oxy = heapq.heappop(pq)

        if u == end:
            return t

        if t > dist[u][oxy]:
            continue

        for v, travel_time, flooded in adj[u]:
            new_oxy = oxy
            if flooded:
                if oxy < travel_time:
                    continue
                new_oxy = oxy - travel_time

            if v in air_set:
                new_oxy = k

            new_t = t + travel_time
            if new_t < dist[v][new_oxy]:
                dist[v][new_oxy] = new_t
                heapq.heappush(pq, (new_t, v, new_oxy))

    return -1
